1	import express from "express";
2	import { createServer as createViteServer } from "vite";
3	import path from "path";
4	import Stripe from "stripe";
5	import { scan } from "./leadEngine/scan.ts";
6	
7	const DEFAULT_ORIGIN = process.env.APP_URL || "http://localhost:3000";
8	const stripeSecret = process.env.STRIPE_SECRET_KEY || "";
9	const stripe = stripeSecret
10	  ? new Stripe(stripeSecret, { apiVersion: "2023-10-16" as any })
11	  : null;
12	
13	function warnIfMissingReleaseEnv() {
14	  const required = ["STRIPE_SECRET_KEY", "APP_URL"];
15	  const missing = required.filter((key) => !process.env[key]);
16	  if (missing.length) console.warn(`[Release] Missing env vars: ${missing.join(", ")}`);
17	}
18	
