1	/**
2	 * Contracts Finder + FTS fetcher
3	 *
4	 * Contracts Finder:
5	 *   Public OCDS endpoint (no auth required):
6	 *   GET https://www.contractsfinder.service.gov.uk/Published/Notices/OCDS/Search
7	 *   Params: publishedFrom, publishedTo, stages, limit, cursor
8	 *
9	 * FTS (Find a Tender Service):
10	 *   Official OCDS release packages endpoint:
11	 *   GET https://www.find-tender.service.gov.uk/api/1.0/ocdsReleasePackages
12	 *   Params: limit, cursor, updatedFrom, updatedTo, stages
13	 */
14	
15	import type { RawLead, SourceStats } from '../types.ts';
16	import { CONFIG } from '../config.ts';
17	
18	// ── CPV prefix → trade mapping (post-fetch filter) ────────────────────────────
19	const CPV_TRADE_PREFIXES: Record<string, string[]> = {
20	  plumbing:    ['45330', '45331', '45332', '45333', '50720', '50730'],
21	  electrical:  ['45310', '45311', '45312', '45315', '45316', '50710', '50711'],
22	  roofing:     ['45260', '45261', '45262', '45263'],
23	  building:    ['45000', '45100', '45200', '45210', '45211', '45220', '45400', '45410', '45450'],
24	  carpentry:   ['45420', '45421', '45422', '45423'],
25	  painting:    ['45440', '45441', '45442'],
26	  hvac:        ['45331', '45332', '50720', '50730'],
27	  landscaping: ['77300', '77310', '77311', '77312', '77313', '77314'],
28	  all:         [],
29	};
30	
31	// Title/description keyword filter when CPV unavailable
32	const TRADE_KEYWORDS: Record<string, RegExp> = {
33	  plumbing:    /plumb|boiler|sanit|hot water|drain|water.*supply/i,
34	  electrical:  /electric|rewire|wiring|lighting|ev.?charg|solar.?pv|power/i,
35	  roofing:     /roof|tile|flat.?roof|epdm|gutter|fascia/i,
36	  building:    /build|construct|refurb|renovat|extension|conversion|maintenance/i,
37	  carpentry:   /carpent|joine|floor|timber|door|window.?frame/i,
38	  painting:    /paint|decorat|plaster|render/i,
39	  hvac:        /hvac|ventilat|air.?con|heat.?pump|ashp|mechanical/i,
40	  landscaping: /landscap|grounds|garden|lawn|horticultur/i,
41	};
42	
43	function matchesTrade(title: string, desc: string, cpvCodes: string[], trade: string): boolean {
44	  if (trade === 'all') return true;
45	  const prefixes = CPV_TRADE_PREFIXES[trade] ?? [];
46	  if (prefixes.length > 0 && cpvCodes.some(c => prefixes.some(p => c.startsWith(p)))) return true;
47	  const re = TRADE_KEYWORDS[trade];
48	  if (re && re.test(`${title} ${desc}`)) return true;
49	  return false;
50	}
51	
52	async function fetchWithTimeout(url: string, opts: RequestInit = {}): Promise<Response> {
53	  let lastErr: unknown;
54	  for (let i = 0; i < CONFIG.retryAttempts; i++) {
55	    try {
56	      const r = await fetch(url, { ...opts, signal: AbortSignal.timeout(CONFIG.fetchTimeoutMs) });
57	      if (r.status === 429) {
58	        const retryAfter = Number(r.headers.get('Retry-After') ?? (i + 1) * 2);
59	        await new Promise(res => setTimeout(res, retryAfter * 1000));
60	        continue;
61	      }
62	      return r;
63	    } catch (e) {
64	      lastErr = e;
