1	/**
2	 * Planning Data fetcher
3	 *
4	 * Endpoint: GET https://www.planning.data.gov.uk/entity.json
5	 * OpenAPI spec: https://www.planning.data.gov.uk/openapi.json
6	 *
7	 * Key params:
8	 *   dataset      — array, e.g. "planning-application"
9	 *   q            — postcode or UPRN text search
10	 *   longitude    — decimal, used with latitude for geo search
11	 *   latitude     — decimal
12	 *   geometry_relation — "within" | "intersects" | "contains" (default "within")
13	 *   period       — "current" (active records only)
14	 *   limit        — max 500, default 10
15	 *   offset       — pagination
16	 *
17	 * Purpose: planning applications → intent signal for future trade work.
18	 * No auth required. Public API.
19	 */
20	
21	import type { RawLead, SourceStats } from '../types.ts';
22	import { CONFIG } from '../config.ts';
23	
24	const PLANNING_ENTITY_URL = 'https://www.planning.data.gov.uk/entity.json';
25	const PLANNING_DATASET = 'planning-application';
26	
27	// Trade → keywords to filter planning descriptions (post-fetch)
28	const TRADE_KEYWORDS: Record<string, RegExp> = {
29	  plumbing:    /plumb|bathroom|kitchen|dwelling|house|extension|conversion/i,
30	  electrical:  /electric|solar|ev|dwelling|house|extension|commercial/i,
31	  roofing:     /roof|dormer|loft|reroofing|house|extension/i,
32	  building:    /extension|conversion|new.?build|house|develop|refurb|construction/i,
33	  carpentry:   /extension|house|conversion|dwelling|timber|joinery/i,
34	  painting:    /house|external|commercial|residential/i,
35	  hvac:        /commercial|office|house|extension|air|ventilat/i,
36	  landscaping: /garden|landscape|grounds|commercial|park|open.?space/i,
37	  all:         /.+/,
38	};
39	
40	function estimateValue(description: string, trade: string): number {
41	  const d = description.toLowerCase();
42	  if (d.includes('loft') || d.includes('dormer'))          return 35_000;
43	  if (d.includes('extension') && d.includes('storey'))     return 40_000;
44	  if (d.includes('extension'))                             return 25_000;
