    landscaping:500,
    all:        500,
  },

  maxValueByTrade: {
    plumbing:   5_000_000,
    electrical: 3_000_000,
    roofing:    5_000_000,
    building:   50_000_000,
    carpentry:  2_000_000,
    painting:   2_000_000,
    hvac:       10_000_000,
    landscaping:5_000_000,
    all:        50_000_000,
  },

  minDeadlineDaysFromNow: 0,   // deadline must be today or future
  maxDeadlineDaysFromNow: 180, // don't show notices 6+ months out

  topN: 25,
  freeTierLimit: 3,
