          <nav className="flex flex-wrap items-center gap-4 text-[12px] font-black uppercase tracking-tight">
            {NAV_ITEMS.map((item) => (
              <Link key={item.to} to={item.to} className="text-white hover:text-[#facc15] transition-colors">
