            <Link to="/demo" className="border-4 border-[#facc15] bg-[#facc15] px-6 py-2 text-lg leading-none text-black">
              GET STARTED
            </Link>
          </nav>
        </div>
      </header>
      {children}
    </div>
  );
}

function CTA({ to = '/demo', label = 'ENTER THE INTAKE' }: { to?: string; label?: string }) {
