  ['DH', 'County Durham'], ['DL', 'County Durham'], ['DN', 'South Yorkshire'],
  ['DT', 'Dorset'], ['DY', 'West Midlands'],
  ['E',  'East London'],
  ['EC', 'City of London'], ['EH', 'Edinburgh'], ['EN', 'Hertfordshire'],
  ['EX', 'Devon'],
  ['FK', 'Stirling'], ['FY', 'Lancashire'],
  ['G',  'Glasgow'], ['GL', 'Gloucestershire'], ['GU', 'Surrey'],
  ['GY', 'Guernsey'],
  ['HA', 'North West London'], ['HD', 'West Yorkshire'], ['HG', 'North Yorkshire'],
  ['HP', 'Hertfordshire'], ['HR', 'Herefordshire'], ['HS', 'Western Isles'],
  ['HU', 'East Yorkshire'], ['HX', 'West Yorkshire'],
  ['IG', 'East London'], ['IP', 'Suffolk'], ['IV', 'Inverness'],
  ['JE', 'Jersey'],
  ['KA', 'Ayrshire'], ['KT', 'Surrey'], ['KW', 'Caithness'], ['KY', 'Fife'],
  ['L',  'Merseyside'], ['LA', 'Lancashire'], ['LD', 'Powys'], ['LE', 'Leicester'],
  ['LL', 'North Wales'], ['LN', 'Lincolnshire'], ['LS', 'West Yorkshire'],
  ['LU', 'Luton'],
  ['M',  'Greater Manchester'], ['ME', 'Kent'], ['MK', 'Milton Keynes'],
  ['ML', 'Glasgow'],
  ['N',  'North London'], ['NE', 'Newcastle'], ['NG', 'Nottingham'],
  ['NN', 'Northamptonshire'], ['NP', 'Newport'], ['NR', 'Norfolk'],
  ['NW', 'North West London'],
  ['OL', 'Greater Manchester'], ['OX', 'Oxford'],
  ['PA', 'Argyll'], ['PE', 'Peterborough'], ['PH', 'Perth'], ['PL', 'Plymouth'],
  ['PO', 'Portsmouth'],
  ['PR', 'Lancashire'],
  ['RG', 'Berkshire'], ['RH', 'Surrey'], ['RM', 'East London'],
  ['S',  'South Yorkshire'], ['SA', 'Swansea'], ['SE', 'South East London'],
  ['SG', 'Hertfordshire'], ['SK', 'Greater Manchester'], ['SL', 'Berkshire'],
  ['SM', 'Surrey'], ['SN', 'Swindon'], ['SO', 'Southampton'],
  ['SP', 'Salisbury'], ['SR', 'Sunderland'], ['SS', 'Essex'],
  ['ST', 'Staffordshire'], ['SW', 'South West London'], ['SY', 'Shropshire'],
  ['TA', 'Somerset'], ['TD', 'Scottish Borders'], ['TF', 'Telford'],
  ['TN', 'Kent'], ['TQ', 'Devon'], ['TR', 'Cornwall'], ['TS', 'Teesside'],
  ['TW', 'Surrey'],
  ['UB', 'West London'],
  ['W',  'West London'], ['WA', 'Cheshire'], ['WC', 'Central London'],
  ['WD', 'Hertfordshire'], ['WF', 'West Yorkshire'], ['WN', 'Greater Manchester'],
  ['WR', 'Worcestershire'], ['WS', 'West Midlands'], ['WV', 'West Midlands'],
  ['YO', 'North Yorkshire'],
  ['ZE', 'Shetland'],
];

export function getOutward(postcode: string): string {
  return postcode.trim().toUpperCase().split(/\s+/)[0];
}

export function regionFromOutward(outward: string): string {
  const clean = outward.toUpperCase();
  // Sort by prefix length descending so longer (more specific) prefixes match first
  const sorted = [...REGION_MAP].sort((a, b) => b[0].length - a[0].length);
  for (const [prefix, region] of sorted) {
    if (clean.startsWith(prefix)) return region;
  }
  return 'United Kingdom';
}

export async function lookupPostcode(postcode: string): Promise<PostcodeInfo> {
  const outward = getOutward(postcode);
  const fallback: PostcodeInfo = { outward, region: regionFromOutward(outward) };
  try {
    const clean = postcode.replace(/\s+/g, '').toUpperCase();
    const r = await fetch(`https://api.postcodes.io/postcodes/${encodeURIComponent(clean)}`, {
      signal: AbortSignal.timeout(4_000),
    });
    if (!r.ok) return fallback;
    const data = await r.json() as any;
    if (data?.status !== 200) return fallback;
    const result = data.result;
    return {
      outward,
      // postcodes.io returns broad ONS regions ("North West", "London") which don't
      // match our directory keys ("Greater Manchester", "East London").
      // Prefer our outward-code map when it's specific; only fall back to postcodes.io
      // for outward codes we don't recognise ("United Kingdom").
      region: fallback.region !== 'United Kingdom'
        ? fallback.region
        : (result.region || result.european_electoral_region || fallback.region),
      adminDistrict: result.admin_district,
      latitude: result.latitude,
      longitude: result.longitude,
    };
  } catch {
    return fallback;
  }
}

// NUTS region codes -> UK regions (used to map FTS delivery locations)
const NUTS_MAP: Record<string, string> = {
  'UKC': 'North East England', 'UKD': 'North West England', 'UKE': 'Yorkshire and the Humber',
  'UKF': 'East Midlands', 'UKG': 'West Midlands', 'UKH': 'East of England',
  'UKI': 'London', 'UKJ': 'South East England', 'UKK': 'South West England',
  'UKL': 'Wales', 'UKM': 'Scotland', 'UKN': 'Northern Ireland',
  'UKC1': 'Tyne and Wear', 'UKC2': 'Northumberland and Durham',
  'UKD1': 'Cumbria', 'UKD3': 'Greater Manchester', 'UKD4': 'Lancashire', 'UKD6': 'Cheshire',
  'UKE1': 'East Yorkshire', 'UKE2': 'North Yorkshire', 'UKE3': 'South Yorkshire', 'UKE4': 'West Yorkshire',
  'UKF1': 'Derbyshire and Nottinghamshire', 'UKF2': 'Leicestershire and Rutland', 'UKF3': 'Lincolnshire',
  'UKG1': 'Herefordshire and Worcestershire', 'UKG2': 'Shropshire and Staffordshire', 'UKG3': 'West Midlands conurbation',
  'UKH1': 'East Anglia', 'UKH2': 'Bedfordshire and Hertfordshire', 'UKH3': 'Essex',
  'UKI3': 'Inner London West', 'UKI4': 'Inner London East', 'UKI5': 'Outer London East',
  'UKI6': 'Outer London South', 'UKI7': 'Outer London West',
  'UKJ1': 'Berkshire, Bucks and Oxon', 'UKJ2': 'Surrey, East and West Sussex', 'UKJ3': 'Hampshire and IoW', 'UKJ4': 'Kent',
  'UKK1': 'Gloucestershire, Wiltshire and Bristol', 'UKK2': 'Dorset and Somerset', 'UKK3': 'Cornwall and IoS', 'UKK4': 'Devon',
  'UKL1': 'West Wales and the Valleys', 'UKL2': 'East Wales',
  'UKM2': 'Eastern Scotland', 'UKM3': 'South Western Scotland', 'UKM5': 'North Eastern Scotland', 'UKM6': 'Highlands and Islands',
};

export function regionFromNuts(nuts: string): string {
  if (!nuts) return '';
  // Try exact match first, then prefix
  if (NUTS_MAP[nuts]) return NUTS_MAP[nuts];
  const prefix = nuts.substring(0, 4);
  if (NUTS_MAP[prefix]) return NUTS_MAP[prefix];
  const prefix3 = nuts.substring(0, 3);
  if (NUTS_MAP[prefix3]) return NUTS_MAP[prefix3];
  return '';
}

// Rough region similarity for scoring — returns 0-1
export function regionSimilarity(regionA: string, regionB: string): number {
  if (!regionA || !regionB) return 0.2;
  const a = regionA.toLowerCase();
  const b = regionB.toLowerCase();
  if (a === b) return 1;
  if (a.includes(b) || b.includes(a)) return 0.8;
  // Both in same broad area
  const broadGroups: string[][] = [
    ['london', 'east london', 'west london', 'north london', 'south east london', 'south west london', 'north west london', 'central london', 'city of london'],
    ['yorkshire', 'west yorkshire', 'south yorkshire', 'east yorkshire', 'north yorkshire'],
    ['manchester', 'greater manchester', 'merseyside', 'lancashire', 'cheshire'],
    ['midlands', 'west midlands', 'east midlands', 'staffordshire', 'worcestershire', 'warwickshire'],
    ['scotland', 'edinburgh', 'glasgow', 'aberdeen', 'dundee', 'inverness', 'stirling'],
    ['wales', 'cardiff', 'swansea', 'newport'],
    ['north east', 'newcastle', 'sunderland', 'teesside', 'county durham'],
  ];
  for (const group of broadGroups) {
    if (group.some(g => a.includes(g)) && group.some(g => b.includes(g))) return 0.6;
  }
  return 0.1;
}

/**
 * Planning Data fetcher
 *
 * Endpoint: GET https://www.planning.data.gov.uk/entity.json
 * OpenAPI spec: https://www.planning.data.gov.uk/openapi.json
 *
 * Key params:
 *   dataset      — array, e.g. "planning-application"
 *   q            — postcode or UPRN text search
 *   longitude    — decimal, used with latitude for geo search
 *   latitude     — decimal
 *   geometry_relation — "within" | "intersects" | "contains" (default "within")
 *   period       — "current" (active records only)
 *   limit        — max 500, default 10
 *   offset       — pagination
 *
 * Purpose: planning applications → intent signal for future trade work.
 * No auth required. Public API.
 */

import type { RawLead, SourceStats } from '../types.ts';
import { CONFIG } from '../config.ts';

const PLANNING_ENTITY_URL = 'https://www.planning.data.gov.uk/entity.json';
// Dataset: 'planning-application' is the correct live dataset on planning.data.gov.uk
const PLANNING_DATASET = 'planning-application';

// Trade → keywords to filter planning descriptions (post-fetch)
const TRADE_KEYWORDS: Record<string, RegExp> = {
  plumbing:    /plumb|bathroom|kitchen|dwelling|house|extension|conversion/i,
  electrical:  /electric|solar|ev|dwelling|house|extension|commercial/i,
  roofing:     /roof|dormer|loft|reroofing|house|extension/i,
  building:    /extension|conversion|new.?build|house|develop|refurb|construction/i,
  carpentry:   /extension|house|conversion|dwelling|timber|joinery/i,
  painting:    /house|external|commercial|residential/i,
  hvac:        /commercial|office|house|extension|air|ventilat/i,
  landscaping: /garden|landscape|grounds|commercial|park|open.?space/i,
  all:         /.+/,
};

function estimateValue(description: string, trade: string): number {
  const d = description.toLowerCase();
  if (d.includes('loft') || d.includes('dormer'))          return 35_000;
  if (d.includes('extension') && d.includes('storey'))     return 40_000;
  if (d.includes('extension'))                             return 25_000;
  if (d.includes('new') && d.includes('dwell'))            return 200_000;
  if (d.includes('conversion'))                            return 50_000;
  if (d.includes('solar') || d.includes('ev'))             return 8_000;
  if (d.includes('commercial'))                            return 80_000;
  const defaults: Record<string, number> = {
    plumbing: 3_000, electrical: 4_000, roofing: 10_000,
    building: 30_000, carpentry: 5_000, painting: 4_000,
    hvac: 12_000, landscaping: 8_000, all: 15_000,
  };
  return defaults[trade] ?? 15_000;
}

export async function planningDataFetcher(
  outward: string,
  _region: string,
  trade: string,
  lat?: number,
  lon?: number,
): Promise<{ leads: RawLead[]; stats: Record<string, SourceStats> }> {

  // Build query — prefer geo lookup, fall back to postcode text search
  const attempts: URLSearchParams[] = [];

  if (lat && lon) {
    // Point search — returns entities near this lat/lon
    const geo = new URLSearchParams();
    geo.append('dataset', PLANNING_DATASET);
    geo.append('latitude', String(lat));
    geo.append('longitude', String(lon));
    geo.set('period', 'current');
    geo.set('limit', '30');
    attempts.push(geo);
  }

  // Postcode outward code text search
  const byPostcode = new URLSearchParams();
  byPostcode.append('dataset', PLANNING_DATASET);
  byPostcode.set('q', outward);
  byPostcode.set('period', 'current');
  byPostcode.set('limit', '30');
  attempts.push(byPostcode);

  // Broad current dataset fallback (no geo filter)
  const broad = new URLSearchParams();
  broad.append('dataset', PLANNING_DATASET);
  broad.set('period', 'current');
  broad.set('limit', '20');
  attempts.push(broad);

  for (const params of attempts) {
    const url = `${PLANNING_ENTITY_URL}?${params}`;
    try {
      const r = await fetch(url, {
        headers: { Accept: 'application/json', 'User-Agent': 'JobFilter/2.0 (jobfilter.uk)' },
        signal: AbortSignal.timeout(CONFIG.fetchTimeoutMs),
      });

      if (!r.ok) {
        console.error(`[Planning] HTTP ${r.status} — ${url}`);
        continue;
      }

      const data = await r.json() as any;
      // API returns { entities: [...], count: n, ... }
      const entities: any[] = data?.entities ?? [];

      if (!entities.length) {
        console.error(`[Planning] 0 entities — ${url}`);
        continue;
      }

      const kw = TRADE_KEYWORDS[trade] ?? TRADE_KEYWORDS.all;

      const leads: RawLead[] = entities
        .filter((e: any) => {
          const text = `${e?.name ?? ''} ${e?.description ?? ''} ${e?.reference ?? ''}`;
          return kw.test(text);
        })
        .map((e: any, i: number) => {
          // planning.data.gov.uk can nest data under json_data or use top-level fields
          const jsonData = e?.json_data ?? e?.data ?? {};
          const desc = String(
            e?.description ?? jsonData?.description ?? jsonData?.development_description ??
            jsonData?.proposal ?? e?.name ?? ''
          ).trim();
          const name = String(e?.name ?? jsonData?.site_name ?? desc).substring(0, 80);
          const address = String(
            e?.address ?? jsonData?.site_address ?? jsonData?.address ?? e?.locality ?? outward
          ).trim();
          return {
            rawId:         String(e?.entity ?? e?.reference ?? `planning-${Date.now()}-${i}`),
            rawTitle:      `Planning Approval: ${name || 'New Development'}`,
            rawDescription:`Approved planning application in ${outward} — potential ${trade} work. Ref: ${e?.reference ?? 'N/A'}. ${desc || 'Development works approved.'}`.substring(0, 300),
            rawValue:      estimateValue(desc || name, trade),
            rawLocation:   address || outward,
            rawPostcode:   outward,
            rawDeadline:   new Date(Date.now() + 30 * 86_400_000).toISOString(),
            rawPublished:  String(e?.['entry-date'] ?? e?.['start-date'] ?? e?.entry_date ?? e?.start_date ?? new Date().toISOString()),
            rawBuyer:      String(e?.organisation ?? e?.['organisation-entity'] ?? jsonData?.applicant_name ?? 'Local Authority').trim(),
            rawCpvCodes:   [],
            sourceSystem:  'PlanningData',
            sourceUrl:     e?.entity ? `https://www.planning.data.gov.uk/entity/${e.entity}` : undefined,
          } satisfies RawLead;
        });

      console.error(`[Planning] ${url} → entities=${entities.length} passed=${leads.length}`);

      const stats: SourceStats = {
        fetched: entities.length,
        passed:  leads.length,
        dropped: entities.length - leads.length,
        failed:  false,
      };
      return { leads, stats: { PlanningData: stats } };

    } catch (err: any) {
      console.error(`[Planning] threw — ${url} — ${err?.message ?? err}`);
      continue;
    }
  }

  // All attempts failed — return empty, do not throw
  console.error(`[Planning] all attempts failed for outward=${outward}`);
  return {
    leads: [],
    stats: {
      PlanningData: {
        fetched: 0, passed: 0, dropped: 0,
        failed: true,
        error: `No successful response for outward=${outward}`,
      },
    },
  };
}

/**
 * scan(postcode, trade) — main lead engine entry point.
 *
 * Pipeline:
 *  1. Resolve postcode → outward, region, lat/lon
 *  2. Run all sources in parallel (ContractsFinder, FTS, PlanningData, DirectorySignal)
 *  3. Normalise raw leads
 *  4. Deduplicate by id
 *  5. Score and rank
 *  6. Return top N with per-source diagnostics
 *
 * Failover: if source fails (any HTTP error or throw) → log + continue.
 * Never blocks on a single source.
 */

import type { Lead, ScanResult, SourceStats } from './types.ts';
import { CONFIG } from './config.ts';
import { lookupPostcode } from './postcode.ts';
import { contractsFetcher } from './fetchers/contractsFetcher.ts';
import { planningDataFetcher } from './fetchers/planningDataFetcher.ts';
import { directorySignalFetcher } from './fetchers/directorySignalFetcher.ts';
import { companiesHouseFetcher } from './fetchers/companiesHouseFetcher.ts';
import { normaliseAll } from './normaliser.ts';
import { scoreLeadBreakdown } from './scorer.ts';

// Endpoint registry — printed in diagnostics
export const SOURCE_ENDPOINTS: Record<string, string[]> = {
  ContractsFinder: [
    'GET  https://www.contractsfinder.service.gov.uk/Published/Notices/OCDS/Search',
  ],
  FTS: [
    'GET  https://www.find-tender.service.gov.uk/api/1.0/ocdsReleasePackages',
  ],
  PlanningData: [
    'GET  https://www.planning.data.gov.uk/entity.json  (geo: ?latitude=&longitude=&dataset=planning-application&period=current)',
    'GET  https://www.planning.data.gov.uk/entity.json  (postcode: ?q={outward}&dataset=planning-application&period=current)',
  ],
  CompaniesHouse: [
    'GET  https://api.company-information.service.gov.uk/advanced-search/companies  (sic_codes=, incorporated_from=, company_status=active)',
    'Requires COMPANIES_HOUSE_API_KEY env var — free at developer.company-information.service.gov.uk',
  ],
  DirectorySignal: [
    '(internal structured dataset — no HTTP call)',
  ],
};

export interface ScanOptions {
  postcode: string;
  trade?: string;
  tier?: 'free' | 'paid';
}

export async function scan(opts: ScanOptions): Promise<ScanResult> {
  const { postcode, trade = 'all', tier = 'free' } = opts;

  // 1. Resolve postcode
  const pcInfo = await lookupPostcode(postcode);
  const { outward, region } = pcInfo;

  // 2. Run all sources concurrently — failures are caught internally
  const [cfResult, planningResult, chResult] = await Promise.allSettled([
    contractsFetcher(trade),
    planningDataFetcher(outward, region, trade, pcInfo.latitude, pcInfo.longitude),
    companiesHouseFetcher(region, trade, outward),
  ]);

  const dirResult = directorySignalFetcher(region, trade, outward); // sync

  // 3. Collect raw leads + merge stats
  const allRaw = [
    ...(cfResult.status === 'fulfilled' ? cfResult.value.leads : []),
    ...(planningResult.status === 'fulfilled' ? planningResult.value.leads : []),
    ...(chResult.status === 'fulfilled' ? chResult.value.leads : []),
    ...dirResult.leads,
  ];

  const mergedStats: Record<string, SourceStats> = {};

  if (cfResult.status === 'fulfilled') {
    Object.assign(mergedStats, cfResult.value.stats);
  } else {
    mergedStats['ContractsFinder'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'ContractsFinder settled as rejected' };
    mergedStats['FTS'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'FTS settled as rejected' };
  }

  if (planningResult.status === 'fulfilled') {
    Object.assign(mergedStats, planningResult.value.stats);
  } else {
    mergedStats['PlanningData'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'Planning settled as rejected' };
  }

  if (chResult.status === 'fulfilled') {
    Object.assign(mergedStats, chResult.value.stats);
  } else {
    mergedStats['CompaniesHouse'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'CompaniesHouse settled as rejected' };
  }

  Object.assign(mergedStats, dirResult.stats);

  // 4. Normalise
  const normalised: Lead[] = normaliseAll(allRaw, trade);

  // 5. Deduplicate by id
  const seen = new Set<string>();
  const unique: Lead[] = [];
  for (const lead of normalised) {
    if (!seen.has(lead.id)) {
      seen.add(lead.id);
      unique.push(lead);
    }
  }

  // 6. Score, update stats.passed, rank
  const scored: Lead[] = unique.map(l => {
    const { score, reasons } = scoreLeadBreakdown(l, region, outward);
    return { ...l, score, scoreReasons: reasons };
  });
  scored.sort((a, b) => (b.score ?? 0) - (a.score ?? 0));

  // Update passed counts from normalised totals
  for (const source of Object.keys(mergedStats)) {
    const count = scored.filter(l => l.source === source).length;
    mergedStats[source].passed = count;
  }

  // 7. Tier gating
  const limit = tier === 'free' ? CONFIG.freeTierLimit : CONFIG.topN;
  const top = scored.slice(0, limit);
  const lockedCount = Math.max(0, scored.length - top.length);

  // 8. Build errors list from failed sources
  const errors: string[] = [];
  for (const [src, stats] of Object.entries(mergedStats)) {
    if (stats.failed) errors.push(`${src}: ${stats.error ?? 'failed'}`);
  }

  return {
    leads: top,
    total: scored.length,
    region,
    outward,
    lockedCount,
    sources: mergedStats,
    errors,
  };
}

// ── CLI runner ────────────────────────────────────────────────────────────────
// Usage: node --import=tsx leadEngine/scan.ts <postcode> [trade] [free|paid]

if (process.argv[1] && process.argv[1].endsWith('scan.ts')) {
  const [,, postcode = 'B15 1AA', trade = 'all', tier = 'free'] = process.argv;

  (async () => {
    console.log('\n╔══════════════════════════════════════════════╗');
    console.log('║          JobFilter Lead Engine v2            ║');
    console.log('╚══════════════════════════════════════════════╝\n');

    console.log('── Sources & Endpoints ──────────────────────────');
    for (const [src, endpoints] of Object.entries(SOURCE_ENDPOINTS)) {
      console.log(`\n  ${src}:`);
      for (const ep of endpoints) console.log(`    ${ep}`);
    }
    console.log('\n── Running scan ─────────────────────────────────');
    console.log(`  Postcode: ${postcode}  Trade: ${trade}  Tier: ${tier}\n`);

    const result = await scan({ postcode, trade, tier: tier as any });

    console.log('── Per-Source Results ───────────────────────────');
    for (const [src, stats] of Object.entries(result.sources)) {
      const status = stats.failed ? '✗ FAIL' : '✓ OK';
      console.log(`  ${status}  ${src.padEnd(20)} fetched=${stats.fetched}  passed=${stats.passed}  dropped=${stats.dropped}${stats.error ? '  ERR=' + stats.error : ''}`);
    }

    if (result.errors.length) {
      console.log('\n── Errors ───────────────────────────────────────');
      for (const e of result.errors) console.log(`  ! ${e}`);
    }

    console.log('\n── Top 10 Leads ─────────────────────────────────');
    const top10 = result.leads.slice(0, 10);
    for (const [i, lead] of top10.entries()) {
      console.log(`\n  ${i + 1}. [${lead.urgency.toUpperCase()}] ${lead.title}`);
      console.log(`     Trade:   ${lead.trade}`);
      console.log(`     Location: ${lead.location}`);
      console.log(`     Value:   ${lead.estimatedValue}`);
      console.log(`     Source:  ${lead.source}  (confidence ${lead.sourceConfidence}%)`);
      console.log(`     Score:   ${lead.score ?? '?'}/100`);
      if ((lead as any).sourceUrl) console.log(`     URL:     ${(lead as any).sourceUrl}`);
    }

    console.log(`\n── Summary ──────────────────────────────────────`);
    console.log(`  Total leads found: ${result.total}`);
    console.log(`  Shown:             ${result.leads.length}`);
    console.log(`  Locked (upgrade):  ${result.lockedCount}`);
    console.log(`  Region:            ${result.region} (${result.outward})\n`);
  })().catch(err => {
    console.error('Scan failed:', err);
    process.exit(1);
  });
}

